package com.kylin.fast.openai.utils;

import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.Base64;
import java.util.Objects;

@Slf4j
public class Base64Tools {

    public static void main(String[] args) throws IOException {
        String data = "";
        File aac = File.createTempFile("1111111111", "aac");
        System.out.println(aac.getAbsoluteFile());
        decodeAndSave(data, aac.getAbsolutePath());
    }

    public static void decodeAndSave(String data, String path) {
        byte[] decode = Base64.getDecoder().decode(data);
        try {
            Files.write(Paths.get(path), decode);
        } catch (IOException e) {
            throw new RuntimeException(e);
        }
    }

    public static String encodeBase64(File file) {
        if (Objects.isNull(file)) {
            return StringUtils.EMPTY;
        }
        try (FileInputStream inputFile = new FileInputStream(file)) {
            byte[] buffer = new byte[(int) file.length()];
            int bytesRead = inputFile.read(buffer);
            if (bytesRead != -1) {
                return Base64.getEncoder().encodeToString(buffer);
            }
            return StringUtils.EMPTY;
        } catch (Exception e) {
            log.error("encode base64 failed", e);
            return StringUtils.EMPTY;
        }
    }
}
